//\! End-to-end tests for mutex poison recovery scenarios.
//\!
//\! These tests verify that rich_rust components remain functional after
//\! mutex poisoning events. Each test includes detailed logging.
//\!
//\! Run with: cargo test --test e2e_mutex_poison -- --nocapture
//\!
//\! Expected output shows step-by-step progress and PASS/FAIL status.

use rich_rust::{Console, ConsoleBuilder, Style, Live, LiveOptions};
use rich_rust::cells::cell_len;
use std::sync::{Arc, Barrier, Mutex};
use std::thread;
use std::time::Duration;
use std::panic;
use std::io::Write;

/// Shared buffer for capturing console output in tests
struct SharedBuffer(Arc<Mutex<Vec<u8>>>);
impl Clone for SharedBuffer {
    fn clone(&self) -> Self { Self(Arc::clone(&self.0)) }
}
impl Write for SharedBuffer {
    fn write(&mut self, buf: &[u8]) -> std::io::Result<usize> {
        self.0.lock().unwrap().extend_from_slice(buf);
        Ok(buf.len())
    }
    fn flush(&mut self) -> std::io::Result<()> { Ok(()) }
}
impl SharedBuffer {
    fn new() -> Self { Self(Arc::new(Mutex::new(Vec::new()))) }
    fn contents(&self) -> String {
        String::from_utf8_lossy(&self.0.lock().unwrap()).to_string()
    }
}

// ============================================================================
// TEST 1: Console operations survive internal mutex poison
// ============================================================================

#[test]
fn test_e2e_console_survives_poison() {
    println\!("\n");
    println\!("=".repeat(70));
    println\!("E2E TEST: Console operations after mutex poison");
    println\!("=".repeat(70));

    let buffer = SharedBuffer::new();
    let console = Arc::new(ConsoleBuilder::new()
        .force_terminal(true)
        .writer(buffer.clone())
        .build());

    println\!("\n[PHASE 1] Baseline: Verify console works normally");
    println\!("-".repeat(50));
    console.print("Initial message");
    let output1 = buffer.contents();
    println\!("  Output captured: {} bytes", output1.len());
    println\!("  Contains 'Initial': {}", output1.contains("Initial"));
    assert\!(output1.contains("Initial"), "Initial print should work");
    println\!("  ✓ Phase 1 PASSED\n");

    println\!("[PHASE 2] Concurrent stress with intentional panics");
    println\!("-".repeat(50));
    let barrier = Arc::new(Barrier::new(6));

    let handles: Vec<_> = (0..6).map(|i| {
        let console = Arc::clone(&console);
        let barrier = Arc::clone(&barrier);

        thread::spawn(move || {
            barrier.wait();

            if i == 2 {
                // This thread will panic
                println\!("  [Thread {}] About to panic intentionally", i);
                panic\!("Intentional panic from thread 2");
            }

            // Other threads print to console
            for j in 0..5 {
                console.print(&format\!("T{}:{}", i, j));
                thread::sleep(Duration::from_millis(5));
            }
            println\!("  [Thread {}] Completed {} prints", i, 5);
        })
    }).collect();

    let mut panicked = 0;
    let mut succeeded = 0;
    for (i, h) in handles.into_iter().enumerate() {
        match h.join() {
            Ok(()) => {
                println\!("  [Thread {}] Joined successfully", i);
                succeeded += 1;
            }
            Err(_) => {
                println\!("  [Thread {}] Panicked (expected)", i);
                panicked += 1;
            }
        }
    }
    println\!("  Summary: {} succeeded, {} panicked", succeeded, panicked);
    assert_eq\!(panicked, 1, "Exactly one thread should panic");
    assert_eq\!(succeeded, 5, "Five threads should succeed");
    println\!("  ✓ Phase 2 PASSED\n");

    println\!("[PHASE 3] Console still works after concurrent panic");
    println\!("-".repeat(50));
    console.print("Final message after chaos");
    let output_final = buffer.contents();
    println\!("  Final output length: {} bytes", output_final.len());
    println\!("  Contains 'Final': {}", output_final.contains("Final"));
    assert\!(output_final.contains("Final"), "Console should still work");
    println\!("  ✓ Phase 3 PASSED\n");

    println\!("=".repeat(70));
    println\!("✓ E2E TEST PASSED: Console survives concurrent panic");
    println\!("=".repeat(70));
    println\!();
}

